mapper.select:
SELECT * FROM diary 
WHERE user_id = #{userId} 
AND create_time BETWEEN #{startDate} AND #{endDate}
ORDER BY create_time DESC

mapper.update:
UPDATE diary
SET 
    title = #{title},
    content = #{content},
    update_time = #{updateTime}
    
        , create_time = #{createTime}
    
WHERE id = #{id}
